const wfData = $('Webhook').first().json.body;
const msg = wfData.message;
const userId = wfData.userId || 'anon';
const sessionId = wfData.sessionId || 'av_' + Date.now();
const businessName = wfData.businessName || 'Cala Blanca';
const tone = (wfData.tone || 'informal').toLowerCase();
const history = wfData.history || [];

// Extraer nombre del mensaje actual
let visitorName = '';
const nameMatch = msg.match(/(?:me llamo|soy|mi nombre es|nombre:?)\s*([A-Za-zÁÉÍÓÚÑáéíóúñ]{2,}(?:\s+[A-Za-zÁÉÍÓÚÑáéíóúñ]{2,}){0,2})/i);
if (nameMatch) visitorName = nameMatch[1].trim();
if (!visitorName) {
  const simpleName = msg.match(/\b(?:soy|me llamo)\s+([A-Za-zÁÉÍÓÚÑáéíóúñ]+)/i);
  if (simpleName) visitorName = simpleName[1];
}

// Extraer contacto con validacion
let visitorContact = '';
const rawPhoneMatch = msg.match(/\b(?:\+?\d{1,3}[-.\s]?)?(\d[\d\s.-]{7,}\d)\b/);
const phoneStr = rawPhoneMatch ? rawPhoneMatch[1] : '';
const phoneDigits = phoneStr.replace(/\D/g, '');
if (phoneDigits.length >= 9) visitorContact = phoneDigits;
if (!visitorContact) {
  const emailMatch = msg.match(/([a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,})/i);
  if (emailMatch) visitorContact = emailMatch[1];
}

// Buscar datos de contacto en historial
let hasContactData = !!(visitorName.length >= 2 || visitorContact.length >= 7);
if (!hasContactData && history.length > 0) {
  const lastUserMsgs = history.filter(h => h.role === 'user').slice(-2);
  for (const h of lastUserMsgs) {
    if (/(?:me llamo|soy|mi nombre|tel[eé]fono|celular|m[oó]vil|whatsapp|contacto|[\d]{7,}|@)/i.test(h.content)) {
      hasContactData = true;
      if (!visitorName) {
        const nm = h.content.match(/(?:me llamo|soy|mi nombre es)\s+([A-Za-zÁÉÍÓÚÑáéíóúñ ]{2,30})/i);
        if (nm) visitorName = nm[1].trim();
      }
      if (!visitorContact) {
        const pm = h.content.match(/\b(?:\+?\d{1,3}[-.\s]?)?(\d[\d\s.-]{7,}\d)\b/);
        const pd = pm ? pm[1].replace(/\D/g, '') : '';
        if (pd.length >= 9) visitorContact = pd;
        if (!visitorContact) {
          const em = h.content.match(/([a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,})/i);
          if (em) visitorContact = em[1];
        }
      }
      break;
    }
  }
}

const kbRows = $('Leer KB').all();

// Extraer config de Telegram desde la KB
let telegramToken = '', telegramChatId = '';
if (kbRows && kbRows.length > 0) {
  for (const r of kbRows) {
    if (r.json.Tema === 'Telegram Token') telegramToken = r.json.Contenido;
    if (r.json.Tema === 'Telegram Chat ID') telegramChatId = r.json.Contenido;
  }
}
let kbText = '';
if (kbRows && kbRows.length > 0) {
  kbText = kbRows.map(r => r.json.Tema + ': ' + r.json.Contenido).join('\n');
}

const toneInstruction = tone === 'formal'
  ? 'Usa "usted" en vez de "tú". Sin coloquialismos ni emojis. Tono profesional.'
  : 'Usa "tú". Tono cercano y de barrio. Puedes usar emojis ocasionalmente.';

const systemPrompt = `Eres el asistente virtual de ${businessName}. Responde de forma amable, natural y concisa. Usa la informacion del negocio para responder.

BASE DE CONOCIMIENTO DEL NEGOCIO:
${kbText}

REGLAS DE ORO:
- Responde en espanol, maximo 2 frases. Se breve y directo.
- ${toneInstruction}
- Si el visitante pregunta precios, disponibilidad o quiere reservar, pide sus datos para comprobar disponibilidad. Dile: "Para confirmarte, necesito tu nombre y un telefono o email. ¿Me los compartes?"
- NUNCA ofrezcas conectar con una persona como primera respuesta cuando el visitante quiere reservar o pregunta precios. PRIMERO pide sus datos (nombre, telefono o email). Solo ofrece contacto humano si rechaza dar sus datos.
- NUNCA pidas datos de contacto en el primer mensaje si el visitante solo saluda o pregunta info general
- Si el visitante TE DA sus datos (nombre, telefono, email), confirmaselos amablemente y dile que le contactaran pronto
- Si preguntan algo que no esta en la base de conocimiento Y no es sobre precios/reservas, se honesto y ofrece conectar con una persona
- ${hasContactData ? 'YA TIENES los datos de contacto de este visitante. NO se los pidas de nuevo.' : ''}
- Si el visitante rechaza dar sus datos, NO insistas. Sigue la conversacion con normalidad.

IMPORTANTE: Al final de tu respuesta agrega SIEMPRE '||RESUMEN:' y en 1-2 frases resume que pregunto el visitante. Ejemplo: 'Son 42€. ||RESUMEN: Pregunto por el precio de la caldereta.' El sistema ocultara el resumen y los datos al usuario. Si el visitante dio su nombre o contacto, agregalos como ||DATOS: nombre=... telefono=... email=...`;

// Construir chatInput para el LLM Chain (system + history + user)
let chatInput = systemPrompt + '\n\n';
const recentHistory = history.slice(-10);
for (const h of recentHistory) {
  chatInput += (h.role === 'user' ? 'Usuario: ' : 'Asistente: ') + h.content + '\n';
}
chatInput += 'Usuario: ' + msg;

return [{
  json: {
    userId, sessionId, message: msg, visitorName, visitorContact,
    hasContactData, businessName, tone, telegramToken, telegramChatId,
    timestamp: new Date().toISOString(),
    chatInput: chatInput,
    systemPrompt: systemPrompt
  }
}];

const data = $input.first().json;
const prepData = $('Prepare DeepSeek').first().json;
const kbRows = $('Leer KB').all();

// Detectar timeout/error del LLM vs respuesta normal
const isApiError = !data || (data.error && !data.text) || (data.message && !data.text);
let text = '';
let iaResumen = '';
let finalName = '', finalContact = '', finalHasContact = false;
let confianza = 'Media';

if (isApiError) {
  // Construir respuesta con datos de contacto del negocio
  let telefono = '', email = '';
  if (kbRows) {
    for (const r of kbRows) {
      if (r.json.Tema === 'Teléfono') telefono = r.json.Contenido;
      if (r.json.Tema === 'Email') email = r.json.Contenido;
    }
  }
  const business = prepData.businessName || 'Cala Blanca';
  text = 'Lo siento, en este momento no puedo procesar tu consulta. Puedes contactar directamente con ' + business +
    (telefono ? ' en ' + telefono : '') +
    (email ? ' o por email a ' + email : '') +
    '. Un miembro de nuestro equipo te atenderá encantado.';
  confianza = 'Baja';
} else {
  let rawContent = data.text || data.output || data.choices?.[0]?.message?.content || '';
  const rawReasoning = data.choices?.[0]?.message?.reasoning_content || '';

  // 1. Tag <response>
  const responseTag = rawContent.match(/<response>([\s\S]*?)<\/response>/i);
  if (responseTag) { text = responseTag[1].trim(); }

  // 2. Marcador 'R:'
  if (!text) {
    const rMatch = rawContent.match(/(?:^|\n)\s*R:\s*(.+?)(?:\n|$)/m);
    if (rMatch) text = rMatch[1].trim();
  }

  // Extraer datos estructurados del LLM: ||DATOS: nombre=X telefono=Y email=Z
  let llmName = '', llmContact = '';
  const datosMatch = rawContent.match(/\|\|DATOS:\s*(.+)$/m);
  if (datosMatch) {
    const datosStr = datosMatch[1];
    const nombreMatch = datosStr.match(/nombre=([^=]+?)(?:\s+telefono=|\s+email=|$)/i);
    const telMatch = datosStr.match(/telefono=([\d\s]+)/i);
    const emailMatch = datosStr.match(/email=([^\s,]+)/i);
    if (nombreMatch) llmName = nombreMatch[1].trim();
    if (telMatch) llmContact = telMatch[1].replace(/\s/g, '');
    if (!llmContact && emailMatch) llmContact = emailMatch[1].trim();
    rawContent = rawContent.replace(/\|\|DATOS:[^\n]*\n?/g, '').trim();
  }
  finalName = llmName || prepData.visitorName || '';
  finalContact = llmContact || prepData.visitorContact || '';
  finalHasContact = !!(finalName.length >= 2 || finalContact.length >= 7);

  // Extraer resumen IA del separador ||RESUMEN:
  if (rawContent.includes('||RESUMEN:')) {
    const parts = rawContent.split('||RESUMEN:');
    rawContent = parts[0].trim();
    iaResumen = (parts[1] || '').trim();
  }

  // 3. Usar el content directamente
  if (!text && rawContent && rawContent.trim().length >= 5) {
    text = rawContent.trim();
  }

  // 4. Fallback si no hay content pero si razonamiento
  if (!text && rawReasoning && rawReasoning.length > 20) {
    let telefono = '', email = '';
    if (kbRows) {
      for (const r of kbRows) {
        if (r.json.Tema === 'Teléfono') telefono = r.json.Contenido;
        if (r.json.Tema === 'Email') email = r.json.Contenido;
      }
    }
    const fallbackBiz = prepData.businessName || 'Cala Blanca';
    text = 'Disculpa, necesito algunos datos para ayudarte mejor.';
  }

  if (!text) text = rawContent || '';
  confianza = (data.choices?.[0]?.finish_reason === 'stop' || data.text || data.output) ? 'Alta' : 'Media';

  if (!text || text.trim().length < 10) {
    text = 'Disculpa, no he podido encontrar una respuesta adecuada.';
    confianza = 'Baja';
  }
}

let estado = 'Rebote';
if (finalHasContact) {
  estado = 'Lead caliente';
} else if (prepData.message && prepData.message.length > 5) {
  estado = 'Consulta';
}

const temas = [];
if (/precio|cu[eá]nto|cuesta|€|euros/i.test(prepData.message)) temas.push('Precios');
if (/reserva|mesa|disponib|fecha|cena|comida/i.test(prepData.message)) temas.push('Reservas');
if (/carta|men[uú]|plato|comida|especialidad/i.test(prepData.message)) temas.push('Carta/Menú');
if (/horario|abren|cierran/i.test(prepData.message)) temas.push('Horario');
if (/donde|c[oó]mo llegar|direcci[oó]n|ubicaci[oó]n/i.test(prepData.message)) temas.push('Ubicación');
if (temas.length === 0) temas.push('General');

const resumen = iaResumen || (temas.join(', ') !== 'General' ? temas.join(', ') + ': ' : '') + '"' + (prepData.message || '').substring(0, 150).replace(/"/g, '') + '"';

return [{
  json: {
    response: text,
    sessionId: prepData.sessionId || 'unknown',
    visitorName: finalName,
    visitorContact: finalContact,
    hasContactData: finalHasContact,
    businessName: prepData.businessName || 'Cala Blanca',
    userMessage: prepData.message || '',
    timestamp: prepData.timestamp || '',
    estado: estado,
    resumen: resumen,
    temas: temas.join(', '),
    confianza: confianza,
    leadCaptured: finalHasContact
  }
}];

const crmRows = $input.all();
const formatData = $('Format Response').first().json;
const currentSessionId = $('Prepare DeepSeek').first().json.sessionId;

let sessionExists = false;
let existingRow = -1;
let existingTemas = '';

for (let i = 0; i < crmRows.length; i++) {
  const rowJson = crmRows[i].json;
  const values = Object.values(rowJson);
  for (const val of values) {
    if (val && val.toString().trim() === currentSessionId) {
      sessionExists = true;
      existingRow = 3 + i;
      existingTemas = rowJson['Temas Preguntados'] || rowJson.temas || rowJson.col_6 || '';
      break;
    }
  }
  if (sessionExists) break;
}

return [{
  json: {
    sessionExists, existingRow, sessionId: currentSessionId,
    visitorName: formatData.visitorName || '',
    visitorContact: formatData.visitorContact || '',
    resumen: formatData.resumen || '',
    estado: formatData.estado || 'Rebote',
    temas: (function() {
      const newTemas = (formatData.temas || 'General').split(', ').filter(function(t) { return t; });
      const oldTemas = existingTemas ? existingTemas.split(', ').filter(function(t) { return t; }) : [];
      if (newTemas.length === 1 && newTemas[0] === 'General' && oldTemas.some(function(t) { return t !== 'General'; })) {
        return existingTemas;
      }
      var merged = [];
      oldTemas.filter(function(t) { return t !== 'General'; }).forEach(function(t) { if (merged.indexOf(t) === -1) merged.push(t); });
      newTemas.filter(function(t) { return t !== 'General'; }).forEach(function(t) { if (merged.indexOf(t) === -1) merged.push(t); });
      return merged.length > 0 ? merged.join(', ') : 'General';
    })(),
    confianza: formatData.confianza || 'Media',
    timestamp: formatData.timestamp || '',
    hasContactData: formatData.hasContactData || false,
    response: formatData.response || ''
  }
}];
